import{_ as a,c as i,o as l,a1 as o}from"./chunks/framework.DDNAyvCW.js";const g=JSON.parse('{"title":"移动端快速上手","description":"","frontmatter":{},"headers":[],"relativePath":"docs/mobile/quickstart/index.md","filePath":"docs/mobile/quickstart/index.md"}'),r={name:"docs/mobile/quickstart/index.md"};function e(s,t,n,d,h,c){return l(),i("div",null,t[0]||(t[0]=[o('<h1 id="移动端快速上手" tabindex="-1">移动端快速上手 <a class="header-anchor" href="#移动端快速上手" aria-label="Permalink to &quot;移动端快速上手&quot;">​</a></h1><p>五步完成 Chaterm 在 iOS 或 Android 上的安装和使用。</p><h2 id="第一步-安装应用" tabindex="-1">第一步：安装应用 <a class="header-anchor" href="#第一步-安装应用" aria-label="Permalink to &quot;第一步：安装应用&quot;">​</a></h2><h3 id="ios" tabindex="-1">iOS <a class="header-anchor" href="#ios" aria-label="Permalink to &quot;iOS&quot;">​</a></h3><ol><li>打开 <a href="https://apps.apple.com/cn/app/chaterm/id6753935895" target="_blank" rel="noreferrer">App Store</a>。</li><li>搜索并安装 <strong>Chaterm</strong>。</li><li>首次启动后按提示完成权限授权。</li></ol><h3 id="android" tabindex="-1">Android <a class="header-anchor" href="#android" aria-label="Permalink to &quot;Android&quot;">​</a></h3><ol><li>打开<a href="/download/">下载页</a>或在应用商店搜索 Chaterm。</li><li>下载最新 Android APK。</li><li>安装 APK 文件，并按系统提示允许安装。</li></ol><div class="tip custom-block"><p class="custom-block-title">建议提前登录</p><p>如果你希望使用数据同步和完整的 AI 功能，建议登录后再开始使用。</p></div><h2 id="第二步-登录账户" tabindex="-1">第二步：登录账户 <a class="header-anchor" href="#第二步-登录账户" aria-label="Permalink to &quot;第二步：登录账户&quot;">​</a></h2><p>Chaterm 移动端支持登录后使用完整能力，也支持先浏览应用再补充登录。可用的登录方式：</p><ul><li><strong>邮箱</strong> -- 接收验证码登录</li><li><strong>账号密码</strong> -- 使用已有凭证登录</li><li><strong>第三方登录</strong> -- 使用 Google、GitHub 或 Apple 登录（以应用当前可用选项为准）</li></ul><h2 id="第三步-添加第一台主机" tabindex="-1">第三步：添加第一台主机 <a class="header-anchor" href="#第三步-添加第一台主机" aria-label="Permalink to &quot;第三步：添加第一台主机&quot;">​</a></h2><ol><li>进入<strong>资产</strong>页面。</li><li>进入<strong>直接连接</strong>，点击右下角 <strong>+</strong> 按钮。</li><li>选择<strong>新建</strong>。</li><li>填写主机标签、IP 地址、端口、用户名等信息。</li><li>选择<strong>密码认证</strong>或<strong>密钥认证</strong>。</li><li>点击<strong>保存</strong>。</li></ol><div class="tip custom-block"><p class="custom-block-title">桌面端同步</p><p>如果你在桌面端开启了数据同步，资产数据会加密同步到移动端。详情请参阅<a href="/docs/mobile/assets/">资产管理</a>。</p></div><h2 id="第四步-建立-ssh-连接" tabindex="-1">第四步：建立 SSH 连接 <a class="header-anchor" href="#第四步-建立-ssh-连接" aria-label="Permalink to &quot;第四步：建立 SSH 连接&quot;">​</a></h2><ol><li>在资产列表中点击目标主机卡片。</li><li>Chaterm 会自动建立 SSH 连接。</li><li>连接成功后进入终端界面。</li></ol><p>常用操作：</p><ul><li><strong>点击</strong>主机卡片直接连接。</li><li><strong>长按</strong>卡片可编辑、收藏或删除。</li><li><strong>搜索</strong>可按主机名、IP、用户名或分组快速筛选。</li></ul><h2 id="第五步-开始使用-ai" tabindex="-1">第五步：开始使用 AI <a class="header-anchor" href="#第五步-开始使用-ai" aria-label="Permalink to &quot;第五步：开始使用 AI&quot;">​</a></h2><p>移动端主要提供两种交互模式：</p><table tabindex="0"><thead><tr><th>模式</th><th>用途</th></tr></thead><tbody><tr><td><strong>终端</strong></td><td>直接执行你输入的命令</td></tr><tr><td><strong>对话</strong></td><td>AI 理解你的需求并建议命令或操作</td></tr></tbody></table><p>基本流程：</p><ol><li>打开 AI 对话页。</li><li>连接目标主机或选择模型。</li><li>在输入框底部切换模式。</li><li>输入问题或命令，或使用语音输入。</li><li>查看执行结果或 AI 返回内容。</li></ol><p>更多详情请参阅 <a href="/docs/mobile/ai-agent/">AI 对话</a>。</p><h2 id="推荐的首次体验" tabindex="-1">推荐的首次体验 <a class="header-anchor" href="#推荐的首次体验" aria-label="Permalink to &quot;推荐的首次体验&quot;">​</a></h2><ol><li>添加一台测试主机。</li><li>发起一次 SSH 连接。</li><li>在<strong>终端</strong>模式下执行 <code>pwd</code> 或 <code>uname -a</code>。</li><li>切换到<strong>对话</strong>模式，询问一个 Linux 命令问题。</li><li>在<strong>个人中心</strong>配置主题、语言和 AI 偏好。</li></ol>',26)]))}const u=a(r,[["render",e]]);export{g as __pageData,u as default};
